// Extract email data from Gmail IMAP node
const item = $input.item.json;

// Extract sender
let senderEmail = 'unknown@unknown.com';
let senderName = '';

if (item.from) {
  // Format: "Name <email@example.com>"
  const match = item.from.match(/(.+?)\s*<(.+?)>/);
  if (match) {
    senderName = match[1].trim();
    senderEmail = match[2].trim();
  } else {
    senderEmail = item.from.trim();
  }
}

// Extract email body - Gmail IMAP returns textPlain and textHtml
let emailContent = item.textPlain || item.text || '';

// Clean up encoding issues (UTF-8 mojibake)
emailContent = emailContent
  .replace(/Ã¼/g, 'ü')
  .replace(/Ã¶/g, 'ö')
  .replace(/Ã¤/g, 'ä')
  .replace(/ÃŸ/g, 'ß')
  .replace(/Ã/g, 'Ä')
  .replace(/Ã/g, 'Ö')
  .replace(/Ã/g, 'Ü');

// Convert date
let receivedDate;
try {
  receivedDate = item.date ? new Date(item.date).toISOString() : new Date().toISOString();
} catch (e) {
  receivedDate = new Date().toISOString();
}

return {
  json: {
    sender_email: senderEmail,
    sender_name: senderName,
    subject: item.subject || 'No Subject',
    email_content: emailContent,
    received_date: receivedDate,
    has_attachments: (item.attachments && item.attachments.length > 0) ? 'yes' : 'no',
    attachment_count: item.attachments?.length || 0
  }
};

// Simple plain-text extraction - no JSON parsing needed
const aiResponse = $input.item.json.generated_text || '';
const emailData = $('Extract Email Data').item.json;

// Clean up AI response - just get the text answer (first line only)
let extractedName = aiResponse.trim().split('\n')[0].trim();

// Remove common AI chatter phrases
extractedName = extractedName.replace(/^(Here is|The sender|The name is|Answer:|Name:)\s*/gi, '').trim();

// If AI returned garbage, too long, or apologizes, use email sender name
if (!extractedName || extractedName.length > 100 || extractedName.toLowerCase().includes('apologize') || extractedName.toLowerCase().includes('email') || extractedName.toLowerCase().includes('signature') || extractedName.toLowerCase().includes('cannot')) {
  extractedName = emailData.sender_name;
}

// Simple rule-based classification
const subject = (emailData.subject || '').toLowerCase();
const content = (emailData.email_content || '').toLowerCase();

let email_type = 'info';
let priority = 'low';
let action_required = 'no';

// Classify email type based on keywords (use English for database constraints)
if (subject.includes('rechnung') || subject.includes('invoice') || content.includes('rechnung')) {
  email_type = 'invoice';
  priority = 'medium';
  action_required = 'yes';
} else if (subject.includes('bestellung') || subject.includes('order') || content.includes('bestellen')) {
  email_type = 'order';
  priority = 'medium';
  action_required = 'yes';
} else if (subject.includes('anfrage') || subject.includes('request') || subject.includes('frage') || subject.includes('kollaboration') || content.includes('zusammenarbeit') || content.includes('termin')) {
  email_type = 'request';
  priority = 'medium';
  action_required = 'yes';
} else if (subject.includes('support') || subject.includes('hilfe') || subject.includes('problem')) {
  email_type = 'support_request';
  priority = 'high';
  action_required = 'yes';
}

// Extract phone number with regex
const phoneMatch = emailData.email_content.match(/\+?[0-9]{1,4}[\s.-]?[(]?[0-9]{1,4}[)]?[\s.-]?[0-9]{3,}[\s.-]?[0-9]{3,}/g);
const phone_number = phoneMatch ? phoneMatch[0] : null;

// Extract meeting times (German and English day names)
const meetingMatch = emailData.email_content.match(/(Montag|Dienstag|Mittwoch|Donnerstag|Freitag|Samstag|Sonntag|Monday|Tuesday|Wednesday|Thursday|Friday)[^\n]*\d{1,2}:\d{2}[^\n]*/gi);
const additional_info = meetingMatch ? 'Terminvorschläge: ' + meetingMatch.join(', ') : null;

// Create simple summary from first 2 sentences of email
let summary = 'Keine Zusammenfassung';
const sentences = emailData.email_content.split(/[.!?]\n/).filter(s => s.trim().length > 20);
if (sentences.length > 0) {
  summary = sentences.slice(0, 2).join('. ').substring(0, 200).trim();
  if (!summary.endsWith('.')) summary += '.';
}

// Build result with ONLY database columns (no extra fields)
const result = {
  sender_name: extractedName,
  sender_email: emailData.sender_email,
  email_type: email_type,
  topic: (emailData.subject || 'Kein Thema').substring(0, 50),
  summary: summary,
  date_deadline: null,
  cost_amount: null,
  phone_number: phone_number,
  priority: priority,
  action_required: action_required,
  additional_info: additional_info,
  original_email: emailData.email_content,
  received_at: emailData.received_date,
  processed_by: 'mistral-7b-simple'
};

return { json: result };

